{
  "grammar": [
    {
      "pattern": "A，然後 B",
      "structure": ["event A", "然後", "event B"],
      "explanation_en": "Use 然後 to connect two past events in chronological order, meaning 'and then' or 'after that'.",
      "title": "Sequencing with 然後",
      "meaning": "Connecting two events in order",
      "when_to_use": ["When telling a story about what happened step by step", "When describing your daily routine or a past sequence"],
      "when_not_to_use": ["When events happen at the same time", "When you want to show cause and effect (use 因為...所以)"],
      "pragmatic_notes": "In Taiwan, 然後 is very common in spoken narratives. You can use it multiple times in a row to keep the story going.",
      "word_order_notes": "然後 always comes between the two events. The first event is stated, then 然後, then the second event.",
      "english_contrast": "English uses 'and then' or 'after that'. Chinese uses 然後 in the same position between clauses.",
      "korean_contrast": "Korean uses 그리고 (geurigo) or 그 다음에 (geu daeume) in a similar way, placed between clauses.",
      "negative_examples": [
        {
          "text": "我昨天去公園然後",
          "error": "然後 needs a second event after it; it cannot be at the end of a sentence."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我昨天去公園，然後我昨天去商店。",
          "error": "Repeating 昨天 is unnecessary; once the time is set, you don't need to repeat it."
        }
      ],
      "transformation_drills": ["Change '我吃早餐。我去公司。' into one sentence using 然後."],
      "production_drills": ["Tell me what you did yesterday morning using 然後 at least once."],
      "common_error_patterns": ["Putting 然後 at the end of a sentence", "Repeating time words unnecessarily"],
      "repair_feedback": {
        "word_order": "Put 然後 between the two events, not at the end.",
        "politeness": "This structure is neutral; no special politeness needed.",
        "vocabulary": "Use simple past events you know, like 吃早餐, 去公司, 看書."
      }
    },
    {
      "pattern": "先 A，然後 B，再 C",
      "structure": ["先", "event A", "然後", "event B", "再", "event C"],
      "explanation_en": "Use 先...然後...再... to list three or more steps in order, meaning 'first A, then B, then C'.",
      "title": "Multiple Steps with 先...然後...再...",
      "meaning": "Listing a sequence of actions",
      "when_to_use": ["When describing a process with three or more steps", "When telling a story with a clear beginning, middle, and end"],
      "when_not_to_use": ["When there are only two steps (use just 然後)", "When the order is not important"],
      "pragmatic_notes": "In Taiwan, this pattern is very common for giving instructions or telling a story. You can add more steps by repeating 然後 or 再.",
      "word_order_notes": "先 comes before the first action, 然後 before the second, 再 before the third. Do not put 先 after the first action.",
      "english_contrast": "English uses 'first...then...then...' or 'first...after that...finally'. Chinese uses 先...然後...再... in the same order.",
      "korean_contrast": "Korean uses 먼저...그리고...그 다음에... (meonjeo...geurigo...geu daeume...) in a similar pattern.",
      "negative_examples": [
        {
          "text": "我先吃早餐，然後去公司，然後看書。",
          "error": "Using 然後 twice is okay but less natural; use 再 for the third step."
        }
      ],
      "incorrect_examples": [
        {
          "text": "先我吃早餐，然後我去公司，再看書。",
          "error": "先 must come right before the verb, not before the subject. Say '我先吃早餐'."
        }
      ],
      "transformation_drills": ["Change '我起床。我刷牙。我吃早餐。' into one sentence using 先...然後...再..."],
      "production_drills": ["Describe your morning routine using 先...然後...再..."],
      "common_error_patterns": ["Putting 先 after the subject instead of before the verb", "Using 然後 for all steps instead of 再"],
      "repair_feedback": {
        "word_order": "先 goes right before the first verb, not before the subject.",
        "politeness": "This pattern is neutral; fine for both casual and polite speech.",
        "vocabulary": "Use daily actions like 起床, 刷牙, 吃早餐, 去公司."
      }
    },
    {
      "pattern": "Subject + Verb + 了 + Object (review)",
      "structure": ["subject", "verb", "了", "object"],
      "explanation_en": "Place 了 after the verb to indicate a completed past action. This is a review of the basic past tense structure.",
      "title": "Past Action with 了 (Review)",
      "meaning": "Indicating a completed action",
      "when_to_use": ["When talking about something that happened and finished in the past", "When answering 'what did you do?' questions"],
      "when_not_to_use": ["When describing habitual actions (use present tense)", "When the action is ongoing or not yet completed"],
      "pragmatic_notes": "In Taiwan, 了 is very common in spoken Chinese for past events. However, for verbs like 是, 有, 在, 了 is not used.",
      "word_order_notes": "了 goes immediately after the verb, before the object. Do not put 了 at the end of the sentence if there is an object.",
      "english_contrast": "English uses past tense (e.g., 'ate'). Chinese uses 了 after the verb. No change in verb form.",
      "korean_contrast": "Korean uses -었/았다 (-eot/atda) at the end of the verb. Chinese places 了 after the verb but before the object.",
      "negative_examples": [
        {
          "text": "我吃了昨天早餐。",
          "error": "Time words like 昨天 should come before the verb, not after the object."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我吃早餐了。",
          "error": "This is correct if there is no object, but with an object like 早餐, 了 should go after the verb: '我吃了早餐'."
        }
      ],
      "transformation_drills": ["Change '我吃早餐' into past tense using 了."],
      "production_drills": ["Tell me one thing you did this morning using 了."],
      "common_error_patterns": ["Putting 了 at the end of the sentence instead of after the verb", "Using 了 with 是 or 有"],
      "repair_feedback": {
        "word_order": "了 goes right after the verb, before the object.",
        "politeness": "This is neutral; no special politeness needed.",
        "vocabulary": "Use simple verbs like 吃, 喝, 看, 去, 買."
      }
    }
  ]
}
